// @ts-nocheck — this module runs in Nuxt's build context, not the consuming app's tsc
import { defineNuxtModule } from '@nuxt/kit'
import { join } from 'pathe'

export default defineNuxtModule({
  meta: { name: 'ontogen-admin' },
  setup(_options, nuxt) {
    // Point #admin-registry at the consuming app's generated file.
    // The consuming app must have app/admin/generated/admin-registry.ts
    // (generated by ontogen's AdminRegistry generator in build.rs).
    nuxt.options.alias['#admin-registry'] = join(
      nuxt.options.rootDir,
      'app/admin/generated/admin-registry',
    )
  },
})
